const input = $json.body || $json;
const cloudMessage = input.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
const rawText = input.Body || input.message || input.text || input.text?.body || cloudMessage?.text?.body || '';
const normalized = String(rawText).trim();
const transactionRegex = /^(masuk|keluar)\s+([\d.]+)\s*(.*)$/i;
const commandOnlyRegex = /^(saldo|laporan bulan ini|pengeluaran bulan ini)$/i;
let command;
let amount;
let description = '';
const commandMatch = normalized.match(commandOnlyRegex);
const transactionMatch = normalized.match(transactionRegex);
if (commandMatch) {
  command = commandMatch[1].toLowerCase();
} else if (transactionMatch) {
  command = transactionMatch[1].toLowerCase();
  amount = Number(transactionMatch[2].replace(/\./g, ''));
  description = (transactionMatch[3] || '').trim();
}
return [{
  json: {
    message: normalized,
    command,
    amount,
    description,
    from: input.From || input.from || cloudMessage?.from || input.sender,
    providerMessageId: input.MessageSid || input.messageId || cloudMessage?.id,
    receivedAt: new Date().toISOString()
  }
}];
